mapper.update:
UPDATE regularization_application
formal_salary = #{formalSalary, typeHandler=com.hrms.crypto.EncryptedBigDecimalTypeHandler}, probation_summary = #{probationSummary}, supervisor_comment = #{supervisorComment}, result_type = #{resultType}, extended_months = #{extendedMonths}, status = #{status},
WHERE id = #{id}

mapper.select:
SELECT ra.id, ra.employee_id, e.name AS employee_name, e.dept_id, d.dept_name, p.position_name, e.entry_date AS hire_date, e.regular_date AS probation_end_date, COALESCE(ra.formal_salary, CAST(ra.formal_salary AS CHAR)) AS formal_salary, ra.probation_summary, ra.supervisor_comment, ra.status, ra.submitter_id, su.username AS submitter_name, ra.create_time, ra.update_time FROM regularization_application ra JOIN employee e ON ra.employee_id = e.id LEFT JOIN department d ON e.dept_id = d.id LEFT JOIN position p ON e.position_id = p.id LEFT JOIN sys_user su ON ra.submitter_id = su.id
AND ra.status = #{status}
AND e.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY ra.create_time DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM regularization_application ra JOIN employee e ON ra.employee_id = e.id
AND ra.status = #{status}
AND e.name LIKE CONCAT('%', #{keyword}, '%')
